# Check error rate on v2 before each step
kubectl exec -n payments deploy/checkout-v2 -c istio-proxy -- \
  pilot-agent request GET stats | grep 'http.inbound.*5xx'

# Bump from 10 to 25
kubectl patch virtualservice checkout -n payments --type=merge -p '{
  "spec":{"http":[{"route":[
    {"destination":{"host":"checkout","subset":"v1"},"weight":75},
    {"destination":{"host":"checkout","subset":"v2"},"weight":25}
  ]}]}
}'

# If something looks bad, snap back to 100/0 in one command
kubectl patch virtualservice checkout -n payments --type=merge -p '{
  "spec":{"http":[{"route":[
    {"destination":{"host":"checkout","subset":"v1"},"weight":100}
  ]}]}
}'

# Without the header: hits v1
curl -s http://checkout.payments/api/version
# {"version":"v1"}

# With the header: hits v2
curl -s -H 'x-canary-user: true' http://checkout.payments/api/version
# {"version":"v2"}
